WITH customer_revenue AS (
  SELECT customer_id, SUM(net_revenue) AS total_revenue FROM revenue_events WHERE period = {period} AND recurring_only = true GROUP BY customer_id
),
ranked AS (
  SELECT customer_id, total_revenue, ROW_NUMBER() OVER (ORDER BY total_revenue DESC) AS rank FROM customer_revenue
),
top_5 AS (
  SELECT SUM(total_revenue) AS top_5_revenue FROM ranked WHERE rank <= 5
),
total AS (
  SELECT SUM(total_revenue) AS total_revenue FROM customer_revenue
)
SELECT COALESCE(t5.top_5_revenue, 0) AS top_5_revenue, COALESCE(t.total_revenue, 0) AS total_revenue, COALESCE(t5.top_5_revenue, 0) * 100.0 / NULLIF(COALESCE(t.total_revenue, 0), 0) AS concentration_risk FROM top_5 t5, total t

WITH revenue AS (
  SELECT SUM(net_revenue) AS total_revenue FROM net_revenue_daily WHERE period = {period}
),
employees AS (
  SELECT AVG(FTE) AS avg_fte FROM employee_fte WHERE period BETWEEN {start_date} AND {end_date}
)
SELECT COALESCE(r.total_revenue, 0) AS total_revenue, COALESCE(e.avg_fte, 0) AS avg_fte, COALESCE(r.total_revenue, 0) / NULLIF(COALESCE(e.avg_fte, 0), 0) AS revenue_per_employee FROM revenue r, employees e

WITH upsell_revenue AS (
  SELECT SUM(net_revenue) AS upsell_revenue FROM orders o JOIN order_items oi ON o.order_id = oi.order_id JOIN upsell_events u ON o.customer_id = u.customer_id AND oi.product_id = u.product_id WHERE o.order_date BETWEEN {start_date} AND {end_date} AND u.upsell_type = 'upgrade'
),
total_revenue AS (
  SELECT SUM(net_revenue) AS total_revenue FROM net_revenue_daily WHERE period = {period}
)
SELECT COALESCE(ur.upsell_revenue, 0) AS upsell_revenue, COALESCE(tr.total_revenue, 0) AS total_revenue, COALESCE(ur.upsell_revenue, 0) * 100.0 / NULLIF(COALESCE(tr.total_revenue, 0), 0) AS upsell_revenue_rate FROM upsell_revenue ur, total_revenue tr

WITH contracts_up_for_renewal AS (
  SELECT contract_id, customer_id FROM contracts WHERE end_date BETWEEN {start_date} AND {end_date} AND status = 'active'
),
renewed AS (
  SELECT contract_id FROM contracts WHERE status = 'renewed' AND renewal_date BETWEEN {start_date} AND {end_date}
),
metrics AS (
  SELECT COUNT(DISTINCT c.contract_id) AS total_up_for_renewal, COUNT(DISTINCT r.contract_id) AS renewed FROM contracts_up_for_renewal c LEFT JOIN renewed r ON c.contract_id = r.contract_id
)
SELECT total_up_for_renewal, renewed, renewed * 100.0 / NULLIF(total_up_for_renewal, 0) AS renewal_rate FROM metrics
